const express = require('express');
const redis = require('redis');
const app = express();
const port = process.env.PORT || 3000;

app.use(express.json());

const redisClient = redis.createClient({
  url: process.env.REDIS_URL || 'redis://localhost:6379'
});

redisClient.on('error', (err) => {
  console.error('Redis Client Error', err);
});

redisClient.connect();

const ALLOWED_COMMANDS = new Set(['GET', 'SET', 'DEL', 'EXISTS', 'TTL', 'KEYS', 'SCAN']);

function validateCommand(command) {
  if (!command || typeof command !== 'string') return false;
  const upperCommand = command.toUpperCase().trim();
  return ALLOWED_COMMANDS.has(upperCommand);
}

function sanitizePattern(pattern) {
  if (!pattern || typeof pattern !== 'string') return '';
  return pattern.replace(/[^\w*?[\]\\]/g, '');
}

app.get('/search', async (req, res) => {
  try {
    const { pattern } = req.query;
    if (!pattern) {
      return res.status(400).json({ error: 'Pattern is required' });
    }
    
    const sanitizedPattern = sanitizePattern(pattern);
    const keys = await redisClient.keys(sanitizedPattern);
    res.json({ keys });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

app.post('/admin', async (req, res) => {
  try {
    const { command, args } = req.body;
    
    if (!validateCommand(command)) {
      return res.status(400).json({ error: 'Invalid command' });
    }
    
    if (!Array.isArray(args)) {
      return res.status(400).json({ error: 'Args must be an array' });
    }
    
    const upperCommand = command.toUpperCase();
    let result;
    
    switch (upperCommand) {
      case 'GET':
        result = await redisClient.get(args[0]);
        break;
      case 'SET':
        result = await redisClient.set(args[0], args[1]);
        break;
      case 'DEL':
        result = await redisClient.del(...args);
        break;
      case 'EXISTS':
        result = await redisClient.exists(...args);
        break;
      case 'TTL':
        result = await redisClient.ttl(args[0]);
        break;
      case 'KEYS':
        const sanitizedPattern = sanitizePattern(args[0]);
        result = await redisClient.keys(sanitizedPattern);
        break;
      case 'SCAN':
        result = await redisClient.scan(args[0], args[1], args[2]);
        break;
      default:
        return res.status(400).json({ error: 'Unsupported command' });
    }
    
    res.json({ result });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

app.listen(port, () => {
  console.log(`Redis Dashboard listening at http://localhost:${port}`);
});